import { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import CountUp from 'react-countup';
import { Grid3X3, UserCheck, Bookmark, Settings } from 'lucide-react';
import { Button } from './ui/button';
import { Avatar, AvatarImage, AvatarFallback } from './ui/avatar';
import { ThemeToggle } from './ThemeToggle';

const StatItem = ({ label, value, suffix = '' }) => {
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
        }
      },
      { threshold: 0.1 }
    );

    if (ref.current) {
      observer.observe(ref.current);
    }

    return () => observer.disconnect();
  }, []);

  return (
    <motion.div 
      ref={ref}
      className="text-center"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
    >
      <span className="font-mono font-bold text-lg md:text-xl text-foreground" data-testid={`stat-${label.toLowerCase()}`}>
        {isVisible ? (
          <CountUp
            end={value}
            duration={2.5}
            separator=","
            suffix={suffix}
            useEasing={true}
          />
        ) : '0'}
      </span>
      <p className="text-xs md:text-sm text-muted-foreground mt-0.5">{label}</p>
    </motion.div>
  );
};

export const ProfileHeader = () => {
  const [isFollowing, setIsFollowing] = useState(false);

  const profileImage = "https://images.unsplash.com/photo-1684132052745-23cd410ecd31?crop=entropy&cs=srgb&fm=jpg&ixid=M3w4NjA1MDZ8MHwxfHNlYXJjaHwyfHxmZW1hbGUlMjBiYWtlciUyMHBvcnRyYWl0JTIwYWVzdGhldGljfGVufDB8fHx8MTc3Mjc0MTU1NXww&ixlib=rb-4.1.0&q=85&w=400";

  return (
    <header className="w-full" data-testid="profile-header">
      {/* Top Navigation Bar */}
      <div className="flex items-center justify-between py-4 px-4 md:px-0 border-b border-border">
        <div className="flex items-center gap-2">
          <h1 className="text-lg font-semibold">sweetdeliriumcookies</h1>
          <svg className="w-4 h-4 text-fuchsia-500" viewBox="0 0 24 24" fill="currentColor">
            <path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/>
          </svg>
        </div>
        <div className="flex items-center gap-2">
          <ThemeToggle />
          <Button variant="ghost" size="icon" className="rounded-full">
            <Settings className="h-5 w-5" />
          </Button>
        </div>
      </div>

      {/* Profile Info Section */}
      <div className="py-6 px-4 md:px-0">
        <div className="flex flex-col md:flex-row items-center md:items-start gap-6 md:gap-10">
          {/* Avatar */}
          <motion.div 
            className="avatar-ring flex-shrink-0"
            initial={{ scale: 0.8, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ duration: 0.5, type: "spring" }}
          >
            <Avatar className="w-24 h-24 md:w-36 md:h-36 border-4 border-background" data-testid="profile-avatar">
              <AvatarImage src={profileImage} alt="@sweetdeliriumcookies" className="object-cover" />
              <AvatarFallback className="bg-fuchsia-500 text-2xl">SD</AvatarFallback>
            </Avatar>
          </motion.div>

          {/* Info */}
          <div className="flex-1 text-center md:text-left">
            {/* Username Row - Desktop */}
            <div className="hidden md:flex items-center gap-4 mb-4">
              <h2 className="text-xl font-normal">sweetdeliriumcookies</h2>
              <motion.div
                whileTap={{ scale: 0.95 }}
              >
                <Button 
                  data-testid="follow-btn"
                  onClick={() => setIsFollowing(!isFollowing)}
                  className={`px-8 ${
                    isFollowing 
                      ? 'bg-secondary text-foreground hover:bg-secondary/80' 
                      : 'bg-fuchsia-500 hover:bg-fuchsia-600 text-white follow-btn-pulse'
                  }`}
                >
                  {isFollowing ? (
                    <span className="flex items-center gap-2">
                      <UserCheck className="w-4 h-4" />
                      Following
                    </span>
                  ) : 'Follow'}
                </Button>
              </motion.div>
              <Button variant="outline" className="px-8">
                Message
              </Button>
            </div>

            {/* Stats Row */}
            <div className="flex justify-center md:justify-start gap-8 md:gap-10 mb-4">
              <StatItem label="posts" value={245} />
              <StatItem label="followers" value={128} suffix="K" />
              <StatItem label="following" value={312} />
            </div>

            {/* Bio */}
            <div className="mt-4">
              <p className="font-semibold text-sm">Sweet Delirium Cookies</p>
              <p className="text-sm text-muted-foreground mt-1">
                Artisan Cookie Creator 🍪<br/>
                Handcrafted with love in NYC<br/>
                <span className="text-fuchsia-400">Custom orders → DM</span>
              </p>
              <p className="text-sm text-fuchsia-400 mt-1 font-medium">
                sweetdeliriumcookies.com
              </p>
            </div>

            {/* Mobile Follow Buttons */}
            <div className="flex gap-2 mt-4 md:hidden">
              <Button 
                data-testid="follow-btn-mobile"
                onClick={() => setIsFollowing(!isFollowing)}
                className={`flex-1 ${
                  isFollowing 
                    ? 'bg-secondary text-foreground' 
                    : 'bg-fuchsia-500 hover:bg-fuchsia-600 text-white'
                }`}
              >
                {isFollowing ? 'Following' : 'Follow'}
              </Button>
              <Button variant="outline" className="flex-1">
                Message
              </Button>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex border-t border-border mt-6 -mx-4 md:mx-0">
          <button className="flex-1 md:flex-none md:px-16 py-3 flex items-center justify-center gap-2 border-t-2 border-foreground -mt-[1px]" data-testid="posts-tab">
            <Grid3X3 className="w-4 h-4" />
            <span className="text-xs font-semibold tracking-wider uppercase">Posts</span>
          </button>
          <button className="flex-1 md:flex-none md:px-16 py-3 flex items-center justify-center gap-2 text-muted-foreground">
            <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <rect x="2" y="2" width="20" height="20" rx="2"/>
              <polygon points="10,8 16,12 10,16" fill="currentColor"/>
            </svg>
            <span className="text-xs font-semibold tracking-wider uppercase">Reels</span>
          </button>
          <button className="flex-1 md:flex-none md:px-16 py-3 flex items-center justify-center gap-2 text-muted-foreground">
            <Bookmark className="w-4 h-4" />
            <span className="text-xs font-semibold tracking-wider uppercase">Saved</span>
          </button>
        </div>
      </div>
    </header>
  );
};
